export type CatalogUiSurface = {
  visible: boolean;
  order?: number;
  width?: string | null;
  variant?: string | null;
};

export type CatalogUiFormSurface = {
  visible: boolean;
  readOnly?: boolean;
  order?: number;
};

export type CatalogUiProposalSurface = {
  editable: boolean;
  order?: number;
};

export type CatalogUiField = {
  key: string;
  control: string;
  label: string;
  labelKey?: string | null;
  format?: string | null;
  list?: CatalogUiSurface | null;
  lookup?: CatalogUiSurface | null;
  form?: CatalogUiFormSurface | null;
  proposal?: CatalogUiProposalSurface | null;
  configurable?: boolean;
  systemOnly?: boolean;
};

export type CatalogUiLookupOptions = {
  searchFieldKeys: string[];
  primaryDisplayKey: string;
  secondaryDisplayKey?: string | null;
  dropdownMatch?: string;
  dropdownMinWidth?: string | null;
};

export type CatalogListHeightMode = 'auto' | 'fixed';

export type CatalogUiListOptions = {
  searchFieldKeys: string[];
  defaultPageSize?: number;
  stickyHeader?: boolean;
  heightMode?: CatalogListHeightMode;
  height?: string | null;
  resizableColumns?: boolean;
};

export type CatalogUiGridConfig = {
  stickyHeader?: boolean;
  heightMode?: CatalogListHeightMode;
  height?: string | null;
  resizableColumns?: boolean;
};

export type CatalogUiTableConfig = {
  masterGrid?: CatalogUiGridConfig;
  detailGrid?: CatalogUiGridConfig;
};

export type CatalogUiSchema = {
  catalogKind: string;
  schemaVersion: number;
  configMode: boolean;
  fields: CatalogUiField[];
  lookup: CatalogUiLookupOptions;
  list: CatalogUiListOptions;
  hintText?: string | null;
  tableConfig?: CatalogUiTableConfig | null;
};

export type SaveCatalogUiSchema = {
  schemaVersion: number;
  fields: CatalogUiField[];
  lookup?: CatalogUiLookupOptions;
  list?: CatalogUiListOptions;
  hintText?: string | null;
  tableConfig?: CatalogUiTableConfig | null;
};

/** SSOT kinds — `GET/PUT /master/catalogs/{kind}/ui-schema` */
export const LIST_UI_SCHEMA_KIND = {
  mesBom: 'mes-bom',
  mesProductionStage: 'mes-production-stage',
  productionOrder: 'production-order',
  mesStageTracking: 'mes-stage-tracking',
} as const;

export function isErpListUiSchemaKind(catalogKind: string): boolean {
  const k = catalogKind.toLowerCase();
  return Object.values(LIST_UI_SCHEMA_KIND).some(kind => kind === k);
}
